import type { QueryState } from './query'

/**
 * Marker used to distinguish a restored persisted snapshot from a normal
 * successful fetch result. Using `Symbol.for` keeps the marker stable across
 * module instances/realms.
 */
const persisterRestoreMarker: unique symbol = Symbol.for(
  'TanStackQueryPersisterRestoreResult',
)

export interface PersisterRestoreResult<
  TData = unknown,
  TError = DefaultError,
> {
  [persisterRestoreMarker]: true
  data: TData | undefined
  state: QueryState<TData, TError>
}

/**
 * Creates the value that a `persister` should return from `prefetchQuery` or a
 * query observer to indicate that a persisted snapshot was restored instead of
 * freshly fetched.
 *
 * When TanStack Query encounters this marker it adopts the provided `state` as
 * the active query state instead of converting the result into a normal success
 * fetch. This preserves stale markers, refetch-error state, failure counters,
 * timestamps, invalidation markers, and infinite-query pagination state.
 */
export function createPersisterRestoreResult<
  TData = unknown,
  TError = DefaultError,
>(result: {
  data: TData | undefined
  state: QueryState<TData, TError>
}): PersisterRestoreResult<TData, TError> {
  return {
    [persisterRestoreMarker]: true,
    data: result.data,
    state: result.state,
  }
}

/**
 * Type guard that detects the restored snapshot marker produced by
 * {@link createPersisterRestoreResult}.
 */
export function isPersisterRestoreResult(
  value: unknown,
): value is PersisterRestoreResult {
  return (
    typeof value === 'object' &&
    value !== null &&
    (value as Partial<PersisterRestoreResult>)[persisterRestoreMarker] === true
  )
}
